var _lastItemTypeCount = 0;
var typeList = [];
var makeList = [];
var modelList = [];
var selectedTypeId = null;
var selectedMakeId = null;
var selectedModelId = null;

function clrErr(g) {
  var el = document.getElementById(g);
  if (el) el.classList.remove('has-err');
  var e = el ? el.querySelector('.err') : null;
  if (e) e.style.display = 'none';
}

function shErr(g, e) {
  var el = document.getElementById(g);
  if (el) el.classList.add('has-err');
  var er = document.getElementById(e);
  if (er) er.style.display = 'block';
}

/* ---------- Item Type search ---------- */
function populateTypeSearch(list) {
  typeList = list || [];
}

function renderTypeOptions(filter) {
  var dd = document.getElementById('type-dropdown');
  if (!dd) return;
  var filtered = filter
    ? typeList.filter(function(t) { return t.item_type_name.toLowerCase().indexOf(filter.toLowerCase()) > -1; })
    : typeList;
  if (!filtered.length) {
    dd.innerHTML = '<div class="search-option no-results">No item types found</div>';
  } else {
    dd.innerHTML = filtered.map(function(t) {
      return '<div class="search-option" data-id="'+t.item_type_id+'" data-label="'+t.item_type_name.replace(/"/g,'&quot;')+'">'+t.item_type_name+'</div>';
    }).join('');
    dd.querySelectorAll('.search-option[data-id]').forEach(function(el) {
      el.addEventListener('click', function() {
        selectedTypeId = this.getAttribute('data-id');
        var label = this.getAttribute('data-label');
        document.getElementById('type-search').value = label;
        document.getElementById('s-type').value = selectedTypeId;
        dd.classList.remove('open');
        clrErr('fg1');
        onTypeSelected(selectedTypeId);
      });
    });
  }
  dd.classList.add('open');
}

function resetTypeSearch() {
  selectedTypeId = null;
  var inp = document.getElementById('type-search');
  var hidden = document.getElementById('s-type');
  var dd = document.getElementById('type-dropdown');
  if (inp) inp.value = '';
  if (hidden) hidden.value = '';
  if (dd) dd.classList.remove('open');
}

function onTypeSelected(v) {
  var db = false;
  var found = typeList.find(function(t) { return String(t.item_type_id) === String(v); });
  if (found) db = !!found.is_data_bearing;
  document.getElementById('tog').checked = db;
  resetMakeSearch();
  document.getElementById('make-search').disabled = !v;
  resetModelSearch();
  Promise.resolve(appsmith.updateModel({ selectedItemTypeId: v, isDataBearing: db })).then(function() {
    appsmith.triggerEvent('onItemTypeChange');
  });
}

/* ---------- Make search ---------- */
function populateMakeSearch(list, keepValue) {
  makeList = list || [];
  var inp = document.getElementById('make-search');
  var hidden = document.getElementById('s-make');
  if (!keepValue) {
    selectedMakeId = null;
    if (inp) inp.value = '';
    if (hidden) hidden.value = '';
  }
  if (inp) inp.disabled = !makeList.length;
}

function renderMakeOptions(filter) {
  var dd = document.getElementById('make-dropdown');
  if (!dd) return;
  var filtered = filter
    ? makeList.filter(function(m) { return m.make_name.toLowerCase().indexOf(filter.toLowerCase()) > -1; })
    : makeList;
  if (!filtered.length) {
    dd.innerHTML = '<div class="search-option no-results">No makes found</div>';
  } else {
    dd.innerHTML = filtered.map(function(m) {
      return '<div class="search-option" data-id="'+m.make_id+'" data-label="'+m.make_name.replace(/"/g,'&quot;')+'">'+m.make_name+'</div>';
    }).join('');
    dd.querySelectorAll('.search-option[data-id]').forEach(function(el) {
      el.addEventListener('click', function() {
        selectedMakeId = this.getAttribute('data-id');
        var label = this.getAttribute('data-label');
        document.getElementById('make-search').value = label;
        document.getElementById('s-make').value = selectedMakeId;
        dd.classList.remove('open');
        clrErr('fg2');
        onMakeSelected(selectedMakeId);
      });
    });
  }
  dd.classList.add('open');
}

function resetMakeSearch() {
  selectedMakeId = null;
  var inp = document.getElementById('make-search');
  var hidden = document.getElementById('s-make');
  var dd = document.getElementById('make-dropdown');
  if (inp) { inp.value = ''; inp.disabled = true; }
  if (hidden) hidden.value = '';
  if (dd) dd.classList.remove('open');
}

function onMakeSelected(v) {
  resetModelSearch();
  Promise.resolve(appsmith.updateModel({ selectedMakeId: v })).then(function() {
    appsmith.triggerEvent('onMakeChange');
  });
}

/* ---------- Model search (unchanged behaviour) ---------- */
function populateModelSearch(list, keepValue) {
  modelList = list || [];
  var inp = document.getElementById('model-search');
  var hidden = document.getElementById('s-model');
  if (!keepValue) {
    selectedModelId = null;
    if (inp) inp.value = '';
    if (hidden) hidden.value = '';
  }
  if (inp) inp.disabled = !modelList.length;
  var btnNm = document.getElementById('btn-nm');
  if (btnNm) btnNm.disabled = !modelList.length;
}

function renderModelOptions(filter) {
  var dd = document.getElementById('model-dropdown');
  if (!dd) return;
  var filtered = filter
    ? modelList.filter(function(m) { return m.model_name.toLowerCase().indexOf(filter.toLowerCase()) > -1; })
    : modelList;
  if (!filtered.length) {
    dd.innerHTML = '<div class="search-option no-results">No models found</div>';
  } else {
    dd.innerHTML = filtered.map(function(m) {
      return '<div class="search-option" data-id="'+m.model_id+'" data-label="'+m.model_name.replace(/"/g,'&quot;')+'">'+m.model_name+'</div>';
    }).join('');
    dd.querySelectorAll('.search-option[data-id]').forEach(function(el) {
      el.addEventListener('click', function() {
        selectedModelId = this.getAttribute('data-id');
        var label = this.getAttribute('data-label');
        document.getElementById('model-search').value = label;
        document.getElementById('s-model').value = selectedModelId;
        dd.classList.remove('open');
        clrErr('fg3');
        appsmith.updateModel({ selectedModelId: selectedModelId });
      });
    });
  }
  dd.classList.add('open');
}

function resetModelSearch() {
  selectedModelId = null;
  var inp = document.getElementById('model-search');
  var hidden = document.getElementById('s-model');
  var dd = document.getElementById('model-dropdown');
  if (inp) { inp.value = ''; inp.disabled = true; }
  if (hidden) hidden.value = '';
  if (dd) dd.classList.remove('open');
  var btnNm = document.getElementById('btn-nm');
  if (btnNm) btnNm.disabled = true;
}

function reset() {
  resetTypeSearch();
  resetMakeSearch();
  resetModelSearch();
  document.getElementById('i-serial').value = '';
  document.getElementById('i-qty').value = '1';
  document.getElementById('i-tag').value = '';
  document.getElementById('tog').checked = false;
  appsmith.updateModel({ autoSelectModelId: null, autoSelectModelName: null });
}

function validate() {
  var ok = true;
  if (!document.getElementById('s-type').value) { shErr('fg1','e-type'); ok = false; }
  if (!document.getElementById('s-make').value) { shErr('fg2','e-make'); ok = false; }
  if (!document.getElementById('s-model').value) { shErr('fg3','e-model'); ok = false; }
  return ok;
}

appsmith.onReady(function() {
  var m = appsmith.model;

  if (m.itemTypes && m.itemTypes.length) {
    _lastItemTypeCount = m.itemTypes.length;
    populateTypeSearch(m.itemTypes);
  }

  if (m.makes && m.makes.length) {
    populateMakeSearch(m.makes);
  }

  if (m.models && m.models.length) {
    populateModelSearch(m.models);
  }

  document.getElementById('c-matched').textContent = m.matchedCount || 0;
  document.getElementById('c-unmatched').textContent = m.unmatchedCount || 0;

  var typeSearchEl = document.getElementById('type-search');
  if (typeSearchEl) {
    typeSearchEl.addEventListener('focus', function() { renderTypeOptions(this.value); });
    typeSearchEl.addEventListener('input', function() { renderTypeOptions(this.value); });
  }

  var makeSearchEl = document.getElementById('make-search');
  if (makeSearchEl) {
    makeSearchEl.addEventListener('focus', function() { renderMakeOptions(this.value); });
    makeSearchEl.addEventListener('input', function() { renderMakeOptions(this.value); });
  }

  var modelSearchEl = document.getElementById('model-search');
  if (modelSearchEl) {
    modelSearchEl.addEventListener('focus', function() { renderModelOptions(this.value); });
    modelSearchEl.addEventListener('input', function() { renderModelOptions(this.value); });
  }

  document.addEventListener('click', function(e) {
    var wraps = ['type-select-wrap', 'make-select-wrap', 'model-select-wrap'];
    wraps.forEach(function(wid) {
      var wrap = document.getElementById(wid);
      if (wrap && !wrap.contains(e.target)) {
        var dd = wrap.querySelector('.search-dropdown');
        if (dd) dd.classList.remove('open');
      }
    });
  });

  document.getElementById('tog').addEventListener('change', function() {
    appsmith.updateModel({ isDataBearing: this.checked });
  });

  document.getElementById('btn-nm').addEventListener('click', function() {
    appsmith.triggerEvent('onNewModel');
  });

  document.getElementById('btn-add').addEventListener('click', function() {
    if (!validate()) return;
    appsmith.updateModel({
      asset: {
        item_type_id: document.getElementById('s-type').value,
        make_id: document.getElementById('s-make').value,
        model_id: document.getElementById('s-model').value,
        serial_no: document.getElementById('i-serial').value.trim(),
        qty: parseInt(document.getElementById('i-qty').value) || 1,
        asset_tag: document.getElementById('i-tag').value.trim(),
        is_data_bearing: document.getElementById('tog').checked
      }
    });
    appsmith.triggerEvent('onAddAsset');
    setTimeout(function() { reset(); }, 1500);
  });

  document.getElementById('btn-confirm').addEventListener('click', function() {
    appsmith.triggerEvent('onConfirmAssets');
  });
});

appsmith.onModelChange(function() {
  var m = appsmith.model;

  if (m.itemTypes && m.itemTypes.length && m.itemTypes.length !== _lastItemTypeCount) {
    _lastItemTypeCount = m.itemTypes.length;
    populateTypeSearch(m.itemTypes);
  }

  if (m.makes) {
    populateMakeSearch(m.makes, !!selectedMakeId);
  }

  if (m.models) {
    populateModelSearch(m.models, !!selectedModelId);
  }

  if (m.autoSelectModelId && String(m.autoSelectModelId) !== String(selectedModelId)) {
    selectedModelId = String(m.autoSelectModelId);
    document.getElementById('s-model').value = selectedModelId;
    document.getElementById('model-search').value = m.autoSelectModelName || '';
    clrErr('fg3');
  }

  if (typeof m.matchedCount !== 'undefined') {
    document.getElementById('c-matched').textContent = m.matchedCount;
  }
  if (typeof m.unmatchedCount !== 'undefined') {
    document.getElementById('c-unmatched').textContent = m.unmatchedCount;
  }

  if (m.resetForm) reset();
});
